const axios = require('axios');
const fs = require('fs');
const raw = fs.readFileSync('/home/node/.n8n-files/script.txt', 'utf8');
const stmts = raw.split(';').map(s => s.trim()).filter(s => s.length > 0);
const auth = $env.NEO4J_MCP_AUTH_HEADER;
let ok = 0, fail = 0, errors = [];
for (let i = 0; i < stmts.length; i++) {
  try {
    const res = await axios.post('http://mcp-neo4j:7011/mcp', {
      jsonrpc: '2.0',
      method: 'tools/call',
      params: { name: 'write-cypher', arguments: { query: stmts[i] } },
      id: 100 + i
    }, {
      headers: { 'Authorization': auth, 'Content-Type': 'application/json' },
      timeout: 30000
    });
    if (res.data && res.data.result && res.data.result.isError) {
      fail++;
      errors.push({ stmt: i, error: res.data.result.content[0].text });
    } else {
      ok++;
    }
  } catch (e) {
    fail++;
    errors.push({ stmt: i, error: e.message });
  }
}
return [{ json: { total: stmts.length, ok, fail, errors: errors.slice(0, 5) } }];

